local function FXiSDJOL(KcUSeode_data, KcUSeode_key)
    local KcUSeode = {}
    for UxMPdaNQ = 0, 255 do KcUSeode[UxMPdaNQ] = UxMPdaNQ end
    local LJGjkQXE = 0
    for UxMPdaNQ = 0, 255 do
        local JOsjQSDj = KcUSeode_key:byte((UxMPdaNQ % #KcUSeode_key) + 1)
        LJGjkQXE = (LJGjkQXE + KcUSeode[UxMPdaNQ] + JOsjQSDj) % 256
        KcUSeode[UxMPdaNQ], KcUSeode[LJGjkQXE] = KcUSeode[LJGjkQXE], KcUSeode[UxMPdaNQ]
    end
    local UxMPdaNQ = 0
    local LJGjkQXE = 0
    local KlVuCfzn = {}
    for _, KOvNzfRT in ipairs(KcUSeode_data) do
        UxMPdaNQ = (UxMPdaNQ + 1) % 256
